const payload = $json.records || $json.items || $json.data || $json.results || [];
const records = Array.isArray(payload) ? payload : [payload];
return records.filter(Boolean).map((record, index) => ({
  json: {
    ...record,
    source_system: $input.first().json.source_system || "source-system",
    source_id: String(record.source_id || record.id || record.accountId || record.opportunityId || index + 1),
    source_url: record.source_url || record.url || record.link || "",
    owner: record.owner || record.accountOwner || record.opportunityOwner || "",
    account_name: record.account_name || record.accountName || record.account || record.company || "",
    opportunity_name: record.opportunity_name || record.opportunityName || record.dealName || "",
    workflow_specific_fields: record,
    raw_record: record,
    run_context: $input.first().json.run_context || {}
  }
}));
